```rust
use std::io::{self, Read};

fn main() -> io::Result<()> {
    let mut buffer = [0u8; 1024]; // A buffer of 1024 bytes

    // Read from stdin to the buffer
    let bytes_read = io::stdin().read(&mut buffer)?;

    // Convert the read bytes to a &str
    let s = std::str::from_utf8(&buffer[..bytes_read])
