fn get_neighbors_with_diagonals(i: usize, j: usize, rows: usize, cols: usize) -> Vec<(usize, usize)> {
    let mut neighbors = Vec::new();

    // Offsets for 8 possible directions: top, bottom, left, right, and 4 diagonals
    let directions = [
        (-1, -1), (-1, 0), (-1, 1), // top-left, top, top-right
        (0, -1), /* (0, 0), */ (0, 1), // left, /* current */, right
        (1, -1), (1, 0), (1, 1), // bottom-left, bottom, bottom-right
