    for (di, dj) in directions.iter() {
        // Using `checked_add` to prevent underflows and overflows
        if let (Some(ni), Some(nj)) = (i.checked_add(*di as usize), j.checked_add(*dj as usize)) {
            if ni < rows && nj < cols {
                neighbors.push((ni, nj));
            }
        }
    }

    neighbors
}

